INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-alcatraz', 'alcatraz', 'www.alcatraz.ai', 'https://www.alcatraz.ai', 'Alcatraz', 'Privacy-focused facial authentication for physical access control and tailgating detection.', 'The clever bet is that AI data centers need a better lock, not another badge reader. Alcatraz turns Face ID into building access with Rock X, edge authentication, 3D liveness, tailgating detection, and opt-in enrollment; it says 5M employees are protected. Unlike surveillance-first facial recognition, the pitch is authentication that forgets the face after the door opens. The risk is whether buyers trust the privacy distinction once regulators get involved.', 5, 'Face ID for secure buildings', 'Other', 'Series B', '$50M', NULL, NULL, NULL, 'US', 'physical security,biometrics,ai infrastructure,access control', 'BlackPeak Capital', NULL, 1, 'alcatraz.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-all3', 'all3', 'www.all3.com', 'https://www.all3.com', 'All3', 'AI design, robotic fabrication, and on-site assembly for buildings.', 'Construction robotics usually breaks between design software and the job site. Unlike prefab software, All3 is trying the harder route: AI-generated architecture, real-time fabrication software, timber components, and Mantis robots that install, fasten, finish, and inspect on site. The public pages claim 100+ in-house engineers and a cost-your-project flow, while TNW reports 100,000+ square meters processed for Germany. The risk is whether vertical integration survives permits and messy sites.', 4, '$25M Seed for construction robots', 'AI / ML', 'Seed', '$25M', NULL, NULL, NULL, 'Europe', 'construction robotics,physical ai,robotic manufacturing,housing', 'RTP Global', '{"linkedin": "https://www.linkedin.com/company/all3"}', 1, 'all3.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-amperos', 'amperos', 'www.amperos.com', 'https://www.amperos.com', 'Amperos', 'AI denial management and insurance collections for providers.', 'Denial management usually dies in workqueues; this tries to make it an owned operating system. Amperos works claims from submission to payment, with AI agents handling payor portals, calls, corrected claims, records, and appeals while RCM specialists cover hard cases. Unlike tools that only draft letters or make calls, the bet is full workflow ownership, visible in 500,000+ claims and 3,000 clinical locations. The risk is healthcare edge cases pulling humans back into the loop.', 4, '$16M Series A for AI denials', 'HealthTech', 'Series A', '$16M', NULL, NULL, NULL, 'US', 'healthcare ai,denial management,revenue cycle,claims', 'Bessemer Venture Partners, Uncork Capital, Neo', '{"linkedin": "https://www.linkedin.com/company/amperos-health"}', 1, 'amperos.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-balerion', 'balerion', 'balerion.ai', 'https://balerion.ai', 'Balerion', 'AI loan-intelligence platform for mortgage origination.', 'The smart move is starting where mortgage files actually break: income math, missing documents, NSF flags, and Fannie/Freddie overlays. Balerion Loan Intelligence is already used by FM Home Loans, a lender managing $2B+ in loan volume, and embeds into existing origination workflows. Unlike point AI tools, it wants to reason across the whole loan file. The risk is enterprise pilots turning into custom services.', 4, '$2B lender using Loan Intelligence', 'Fintech', 'Seed', '$6M', NULL, NULL, NULL, 'US', 'mortgage,ai agents,fintech,loan origination', 'Kleiner Perkins', '{"twitter": "https://x.com/BalerionAI", "linkedin": "https://www.linkedin.com/company/balerion-ai/"}', 0, 'balerion.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-basata', 'basata', 'www.basata.ai', 'https://www.basata.ai', 'Basata', 'AI referral intake and call handling for specialty practices.', 'Healthcare AI usually chases clinicians; this aims at the fax pile between referral and visit. Basata processes faxes, creates EHR charts, calls patients with voice agents, and claims 500,000 referrals processed with 100,000 in the last month. Unlike ambient scribes, the bet is owning the handoff before care starts. The risk is how much specialty-specific workflow knowledge has to be rebuilt practice by practice.', 4, '$21M Series A for referral ops', 'HealthTech', 'Series A', '$21M', NULL, NULL, NULL, 'US', 'healthcare ai,referrals,voice agents,practice operations', 'Basis Set Ventures, Cowboy Ventures, Sofeon', NULL, 1, 'basata.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-branchlab', 'branchlab', 'branchlab.com', 'https://branchlab.com/pathwai', 'BranchLab', 'AI audience platform for pharma commercialization.', 'The sharper idea is removing PHI from pharma targeting instead of pretending healthcare marketing is ordinary ads. Pathwai learns from de-identified health signals, clusters patient journeys, and cites outcomes like 2,000 extra patients reached in three weeks and 90% lower cost per patient. Compared with static audience files, it sells a learning system for commercial teams. The risk is whether better targeting feels like better healthcare to anyone outside pharma.', 5, '2,000 patients in 3 weeks', 'HealthTech', 'Series A', '$26M', NULL, NULL, NULL, 'US', 'pharma,healthcare ai,audience targeting,commercialization', 'McKesson Ventures', NULL, 1, 'branchlab.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-cal-com', 'cal-com', 'cal.com', 'https://cal.com', 'Cal.com', 'Open source scheduling infrastructure.', 'The interesting move was not cloning Calendly in public. It was treating scheduling as infrastructure: a self-hosted option, API hooks, and a hosted product for teams that do not want to run it themselves. That is a sharper bet than generic booking software. Cal.com is selling control, not just calendar pages.', 4, 'Open source done right', 'SaaS', 'Series A', '$25M', 2021, '30-50', 'San Francisco', 'US', 'scheduling,open source,calendar,productivity', 'Dick Costolo, Joseph Jacks (OSS Capital), Peer Richelsen', '{"github": "https://github.com/calcom/cal.com", "twitter": "https://x.com/calabordar", "linkedin": "https://linkedin.com/company/cal-com"}', 0, 'cal-com.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-ciridae', 'ciridae', 'www.ciridae.com', 'https://www.ciridae.com', 'Ciridae', 'AI operating systems for real-economy businesses.', 'The sharper bet is that mid-market operators need rebuilt workflows, not another AI sidebar. Ciridae shows AP invoices, CRM, reporting, project management, and Knight case metrics like $5M revenue uplift and 100% of A/P invoices processed. Unlike horizontal copilots, it embeds into how restoration or logistics companies already run. The risk is whether services work scales without becoming consulting.', 5, '100% AP invoices processed', 'AI / ML', 'Seed', '$20M', NULL, NULL, NULL, 'US', 'ai operations,industrial services,private equity,workflow automation', 'Accel, Andreessen Horowitz, General Catalyst', NULL, 1, 'ciridae.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-config', 'config', 'config.inc', 'https://config.inc/product', 'Config', 'Robot training-data platform for robotics foundation models.', 'The strongest bet is that robot data should be fabricated like semiconductors, not collected one lab at a time. Config''s platform walks from gripper design to data strategy, acquisition, labeling, action estimation, model training, and evaluation; CFG-1 claims 100K in-house human-data hours, 2B parameters, and sub-50ms RTX 5090 latency. Compared with robot builders chasing hardware, this sells the data foundry. The risk is that customers still need proof on their own factory tasks.', 4, '100K hours of robot data', 'AI / ML', 'Seed', '$27M', NULL, NULL, NULL, 'China / Asia', 'robotics,training data,foundation models,physical ai', 'Samsung Venture Investment', NULL, 0, 'config.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-copilotkit', 'copilotkit', 'www.copilotkit.ai', 'https://www.copilotkit.ai', 'CopilotKit', 'Open-source framework for app-native AI agents and generative UI.', 'Most agent products still end at a chat box; the sharper bet is giving agents a front end. CopilotKit exposes React and Angular SDKs, AG-UI, MCP Apps, threads, GitHub-backed docs, and a one-command npx path. Unlike Vercel''s AI SDK or ChatGPT Apps, it is trying to be the neutral UI layer enterprises can self-host. The risk is that protocol gravity is hard to keep once platform vendors bundle the same primitives.', 5, 'AG-UI for app-native agents', 'DevTools', 'Series A', '$27M', NULL, NULL, NULL, 'US', 'ai agents,generative ui,developer tools,open source', 'Glilot Capital, NFX, SignalFire', '{"github": "https://github.com/CopilotKit/CopilotKit", "twitter": "https://x.com/CopilotKit", "linkedin": "https://www.linkedin.com/company/copilotkit/"}', 1, 'copilotkit.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-corgi', 'corgi', 'www.corgi.insure', 'https://www.corgi.insure', 'Corgi', 'Instant startup insurance quotes and modular coverage.', 'Startup insurance usually feels like paperwork wearing a broker''s suit; this is closer to checkout. Corgi exposes instant quotes, 4 stage-based coverage paths, D&O, Cyber, Tech E&O, and customer proof from Deel, Bland, Intryc, and other startups. Unlike Vouch or Embroker, the bet is that founders want insurance to feel as fast as buying compute. The risk is that underwriting speed has to survive messier companies than YC-style software teams.', 5, '$160M Series B for instant insurance', 'Fintech', 'Series B', '$160M', NULL, NULL, NULL, 'US', 'insurance,fintech,startups,founder tools', 'TCV, Kindred Ventures, Leblon Capital, First Order Fund', '{"twitter": "https://x.com/UseCorgi", "linkedin": "https://www.linkedin.com/company/corgi-insurance"}', 1, 'corgi.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-cursor', 'cursor', 'cursor.com', 'https://cursor.com', 'Cursor', 'The AI-first code editor.', 'The right bet was not copilot-inside-VSCode, but an editor rebuilt around the model. Tab completion, inline diffs, and cmd-K feel native rather than bolted on. By forking VS Code instead of starting from scratch, Cursor kept the muscle memory and changed the center of gravity. That is why it feels sticky instead of merely novel.', 5, 'Changed how developers write code', 'AI / ML', 'Series A', '$60M', 2022, '50-100', 'San Francisco', 'US', 'ai,code editor,developer tools,productivity', 'Andreessen Horowitz, Thrive Capital, OpenAI Startup Fund', '{"github": "https://github.com/getcursor", "twitter": "https://x.com/cursor_ai", "linkedin": "https://linkedin.com/company/cursor-ai"}', 1, 'cursor.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-eleven-labs', 'eleven-labs', 'elevenlabs.io', 'https://elevenlabs.io', 'ElevenLabs', 'AI voice generation and speech synthesis platform.', 'The surprising thing is not that voice cloning works. It is that 30 seconds of audio can already get you something commercially usable. ElevenLabs is betting this becomes infrastructure for dubbing, audiobooks, and accessibility, not just a viral demo. That is a narrower and more durable business than AI voice as spectacle.', 4, 'Voice AI that actually sounds human', 'AI / ML', 'Series B', '$80M', 2022, '50-100', 'New York', 'US', 'voice ai,speech synthesis,text to speech,artificial intelligence', 'Andreessen Horowitz, Nat Friedman, Daniel Gross', '{"github": "https://github.com/elevenlabs", "twitter": "https://x.com/elevenlabsio", "linkedin": "https://linkedin.com/company/elevenlabs"}', 0, 'eleven-labs.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-enzo-health', 'enzo-health', 'www.enzo.health', 'https://www.enzo.health', 'Enzo Health', 'Home health intake, scribe, and QA workflows with AI.', 'Home health software often treats the nurse as the data-entry layer; this pushes the paperwork into the visit itself. Enzo shows Intake, Scribe, and QA modules with OASIS validation, referral checks, secure messaging, and 5-minute intake-to-admission claims. Unlike generic medical scribes, the bet is one thread from bedside note to reimbursement. The risk is integrating deeply enough with fragmented agency systems.', 4, '$20M Series A for home health AI', 'HealthTech', 'Series A', '$20M', NULL, NULL, NULL, 'US', 'home health,clinical documentation,intake,quality assurance', 'N47, Gradient, Tandem Ventures, Rigby Watts', NULL, 1, 'enzo-health.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-ethos', 'ethos', 'agent.askethos.com', 'https://agent.askethos.com', 'Ethos', 'AI-matched expert network with voice-based onboarding.', 'The sharper idea is that expert networks should know what people can do, not just what titles they held. Ethos uses voice onboarding, public-source enrichment, paid opportunity cards, and 35,000 weekly expert joins to build a deeper matching layer. Unlike LinkedIn search or GLG-style forms, the bet is that interviews create a better skill graph than resumes. The risk is quality control once the network scales faster than its eight-person team.', 5, '35K experts joining each week', 'Marketplace', 'Series A', '$22.75M', NULL, NULL, NULL, 'Europe', 'expert network,ai matching,voice onboarding,marketplace', 'Andreessen Horowitz, General Catalyst, XTX Markets, Evantic Capital, Common Magic', NULL, 1, 'ethos.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screens