INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-fazeshift', 'fazeshift', 'www.fazeshift.com', 'https://www.fazeshift.com', 'Fazeshift', 'AI accounts receivable agents for finance teams.', 'The bet is boring on purpose: automate the cash cycle inside the systems finance teams already trust, not replace them. Fazeshift shows cash application, collections, contract review, Stripe/NetSuite/Sage Intacct billing, SOC 1/2, and customer claims like 50% DSO reduction. Unlike generic finance copilots, each agent maps to a stubborn AR job. The test is whether invoice edge cases stay tractable at scale.', 5, '$22M Series A for AR agents', 'Fintech', 'Series A', '$22M', NULL, NULL, NULL, 'US', 'accounts receivable,finance ops,ai agents,billing automation', 'F-Prime Capital', NULL, 1, 'fazeshift.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-featherless', 'featherless', 'featherless.ai', 'https://featherless.ai', 'Featherless', 'Serverless API access to 30,000+ open-weight AI models.', 'The bet is open-model inference without renting a GPU box or accepting a closed API. Featherless exposes 30,000+ models through one API, docs for chat completions, embeddings, tool calling, vision, and a live model library with usage counts. Unlike raw GPU clouds, it sells model choice and predictable pricing as the product. The hard part is keeping that promise when every niche model wants different hardware.', 5, '$20M Series A for 30K models', 'DevTools', 'Series A', '$20M', NULL, NULL, NULL, 'Global / Remote', 'ai infrastructure,inference,open models,developer tools', 'AMD Ventures', NULL, 1, 'featherless.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-gizmo', 'gizmo', 'gizmo.ai', 'https://gizmo.ai', 'Gizmo', 'AI study app that turns notes into flashcards, quizzes, and streak-based learning loops.', 'Most study apps still behave like digital stationery; the sharper move is designing for the attention span TikTok trained instead. Gizmo pairs AI-generated flashcards with streaks, leaderboards, limited lives, and social challenges; it reaches 13 million users in 120 countries. Instead of asking students to become more disciplined, it is betting that better habits can piggyback on addictive product design. The risk is that engagement mechanics outrun learning depth once the novelty wears off.', 5, 'TikTok loops for studying', 'EdTech', 'Series A', '$22M', NULL, NULL, NULL, 'Europe', 'education,study tools,flashcards,consumer app', 'Shine Capital, Ada Ventures, Seek Investments, GSV, NFX', NULL, 1, 'gizmo.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-govwell', 'govwell', 'www.govwell.com', 'https://www.govwell.com', 'GovWell', 'AI permitting and licensing platform for local governments.', 'This is civic software with a painfully concrete wedge: permits, inspections, licenses, and code enforcement instead of vague government change. GovWell shows AI AutoCheck, 5,000+ processes, 100+ agencies, 35+ states, and processing that can move from 10 days to under an hour. Unlike legacy municipal systems, the product sells speed without making staff change departments. Procurement pace is the obvious drag.', 5, '100+ agencies, $25M Series A', 'SaaS', 'Series A', '$25M', NULL, NULL, NULL, 'US', 'civic software,permitting,licensing,local government', 'Insight Partners', NULL, 1, 'govwell.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_