INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-grai', 'grai', 'www.grai.fm', 'https://www.grai.fm', 'GRAI', 'Social AI music app for remixing songs with friends while keeping artist control in the loop.', 'Most AI music tools treat listeners like failed producers; the better consumer bet is participation without pretending everyone wants a DAW. GRAI is live as an iPhone app and raised a $9M seed round, letting people react to friends'' tracks and flip songs into new moods. Unlike Suno or Udio, it starts from existing music and artist opt-in rather than blank-page generation. The hard part is whether labels give enough catalog access for the social loop to matter.', 4, 'Social remix, not song gen', 'Creator Tools', 'Seed', '$9M', NULL, NULL, NULL, 'Europe', 'music,ai,remix,social apps,creator tools', 'Khosla Ventures, Inovo VC', '{"linkedin": "https://www.linkedin.com/company/grai-fm/"}', 1, 'grai.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-granola', 'granola', 'www.granola.ai', 'https://www.granola.ai', 'Granola', 'AI meeting notes that turn transcripts into searchable team context.', 'Meeting notes only looked saturated until someone removed the bot and treated meetings as company memory instead. Granola''s local transcription, MCP server, and new personal plus enterprise APIs make it feel closer to context infrastructure than another transcript widget. Where most note-takers sell recall, this is betting that shared context matters more than summaries. The risk is that the product loses elegance as it stretches from a sharp Mac app into enterprise workflow plumbing.', 5, 'Bot-free meeting context layer', 'SaaS', 'Series C', '$125M', NULL, NULL, NULL, 'Europe', 'meeting notes,productivity,knowledge management,ai assistant', 'Index Ventures, Kleiner Perkins, Lightspeed Venture Partners, Spark Capital, NFDG', '{"twitter": "https://x.com/meetgranola", "linkedin": "https://www.linkedin.com/company/meetgranola"}', 1, 'granola.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-hilbert', 'hilbert', 'hilberts.ai', 'https://hilberts.ai', 'Hilbert', 'AI growth infrastructure for B2C revenue decisions.', 'Growth analytics usually stops at dashboards; this is trying to become the decision layer after the chart. Hilbert shows anomaly detection, root-cause analysis, counterfactuals, pLTV targeting, and agent-driven growth tasks in one product surface. Unlike BI tools or in-house ML projects, the bet is that B2C teams want actions tied to cohorts and unit economics, not another report. The risk is proving those actions move revenue outside the demo data.', 4, '$28M Series A for growth infra', 'AI / ML', 'Series A', '$28M', NULL, NULL, NULL, 'US', 'growth analytics,b2c ai,decision intelligence,marketing', 'Andreessen Horowitz', NULL, 1, 'hilbert.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-juliahub', 'juliahub', 'juliahub.com', 'https://juliahub.com', 'JuliaHub', 'Agentic simulation and digital-twin tooling for hardware engineering teams.', 'Someone finally treated engineering simulation like a software workflow, not a CAD afterthought. Dyad 3.0 turns Julia models, SciML, case studies, and cloud runs into an AI-native workspace for physical systems, with public proof from ASML, Boeing, NASA, and Williams Racing. The bet is that hardware teams want agents constrained by equations rather than chatbots guessing at parts. The risk is whether that craft reaches engineers outside the Julia faithful.', 5, '$65M Series B for Dyad 3.0', 'AI / ML', 'Series B', '$65M', NULL, NULL, NULL, 'US', 'scientific ai,simulation,digital twins,hardware engineering', 'Dorilton Ventures', NULL, 1, 'juliahub.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-krea', 'krea', 'www.krea.ai', 'https://www.krea.ai', 'Krea', 'AI creative suite for generating, editing, and controlling images, video, and 3D assets.', 'Creative AI gets interesting when it treats models as material instead of magic boxes. Krea puts Krea 1, video, enhancer, realtime, editing, LoRA training, and style transfer into one workspace; the app exposes prompt, model, ratio, and resolution controls before it asks for a sales call. Unlike prompt-only wrappers, the bet is that visual creators want handles they can keep adjusting. The risk is that bundling every medium can blur the point if the controls stop feeling precise.', 5, 'Krea 1 plus visual control handles', 'Creator Tools', 'Series B', '$47M', NULL, NULL, NULL, 'US', 'ai creative tools,image generation,video generation,design tools', 'Bain Capital Ventures, Andreessen Horowitz, Abstract Ventures', '{"github": "https://github.com/krea-ai", "twitter": "https://x.com/krea_ai", "linkedin": "https://www.linkedin.com/company/krea-ai"}', 1, 'krea.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = exclu