INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-manifest-os', 'manifest-os', 'manifestos.com', 'https://manifestos.com', 'Manifest OS', 'AI-native legal-services platform for fixed-fee immigration firms.', 'Someone finally attacked legal AI from the business model, not the Word add-in. Manifest OS powers immigration firms with fixed-fee pricing, a client portal, AI Drafter, AI Case Evaluation, and 3,000+ handled engagements. Unlike Harvey-style copilot tools, the bet is to operate the service stack and reinvest firm profits into R&D. The risk is bar-by-bar regulation slowing the model outside Arizona.', 5, '$60M Series A, 3,000+ engagements', 'Other', 'Series A', '$60M', NULL, NULL, NULL, 'US', 'legal tech,ai agents,immigration,services', 'Menlo Ventures', '{"linkedin": "https://www.linkedin.com/company/manifest-os/"}', 1, 'manifest-os.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screensh