INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-monk', 'monk', 'monk.com', 'https://monk.com', 'Monk', 'AI accounts receivable platform for invoices, collections, cash application, and disputes.', 'The smart move is treating accounts receivable as customer infrastructure, not back-office nagging. Monk handles contract-to-cash work like invoice creation, collections, cash application, portal uploads, PO mismatches, and disputes, with reported 40% lower DSO. Unlike generic finance automation, the product is built around the ugly exceptions that actually delay cash. The risk is that services-heavy onboarding hides how much of the product is software.', 5, 'AR edge cases, not reminders', 'Fintech', 'Series A', '$25M', NULL, NULL, NULL, 'US', 'accounts receivable,finance automation,ai agents,b2b', 'Footwork', NULL, 1, 'monk.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workfl