INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-origin-lab', 'origin-lab', 'originlab.ai', 'https://originlab.ai', 'Origin Lab', 'Licensed game-engine data for AI world models and robotics simulation.', 'The interesting bet is that world models need game-engine state, not scraped video. Origin Lab captures HUD-free gameplay with depth, action, camera, scene metadata, 20+ categories, 50+ licensed titles, and same-day API access for evals. Compared with web video datasets, this has rights provenance and physics-adjacent telemetry. The hard part is whether game worlds transfer to messy real-world robotics.', 4, 'Game-engine data for world models', 'AI / ML', 'Seed', '$8M', NULL, NULL, NULL, 'US', 'world models,training data,video games,synthetic data', 'Lightspeed Venture Partners', NULL, 0, 'origin-lab.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = exclude