INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-parallel-web-systems', 'parallel-web-systems', 'parallel.ai', 'https://parallel.ai', 'Parallel Web Systems', 'Web search, extraction, monitoring, and research APIs for AI agents.', 'The sharper bet is that AI agents need web infrastructure, not another consumer search box. Parallel exposes Search, Extract, Task, FindAll, Chat, and Monitor APIs, plus OpenAPI, Python, and TypeScript SDKs. Unlike browser wrappers that pretend pages are stable, this treats the web as a programmatic substrate with benchmarks and case studies attached. The risk is that model providers pull the same interfaces into their own platforms.', 5, 'Web APIs for AI agents', 'DevTools', 'Series B', '$100M', 2023, '10-30', 'San Francisco', 'US', 'ai agents,web search,api,developer tools', 'Sequoia Capital, Index Ventures, Khosla Ventures', '{"github": "https://github.com/parallel-web", "twitter": "https://x.com/p0", "linkedin": "https://www.linkedin.com/company/parallel-web/"}', 1, 'parallel-web-systems.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, in