INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-parasail', 'parasail', 'parasail.io', 'https://parasail.io', 'Parasail', 'Serverless and dedicated GPU inference for AI teams.', 'The practical bet is inference without the cloud procurement tax. Parasail leads with no quotas, no long contracts, up to 30x lower pricing, and docs for Serverless, Dedicated endpoints, Batch, Responses API, and billing APIs. Compared to renting raw GPU boxes, it sells a model-running surface that can scale from free credits to 500B+ daily tokens. The open question is whether this stays cheaper once the largest clouds copy the packaging.', 4, '500B+ tokens served daily', 'DevTools', 'Series A', '$32M', 2023, '10-30', 'San Francisco', 'US', 'gpu cloud,inference,ai infrastructure,developer tools', 'Touring Capital, Kindred Ventures, Basis Set, Samsung Next', '{"twitter": "https://x.com/parasail_io", "linkedin": "https://www.linkedin.com/company/parasail-io/"}', 1, 'parasail.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-perplexity', 'perplexity', 'perplexity.ai', 'https://perplexity.ai', 'Perplexity', 'AI-powered answer engine that searches the web.', 'Answer-first search should have existed years ago. Perplexity makes the core interaction brutally simple: ask a question, get a synthesized answer with sources, not ten blue links and ad clutter. That is a sharp product bet against the browsing-heavy search interface. The open question is whether that habit expands beyond power users.', 5, 'The Google killer that might actually be', 'AI / ML', 'Series B', '$73.6M', 2022, '100-200', 'San Francisco', 'US', 'ai search,answer engine,web search,artificial intelligence', 'IVP, NEA, Databricks Ventures, Jeff Bezos', '{"twitter": "https://x.com/perabordar", "linkedin": "https://linkedin.com/company/perplexity-ai"}', 1, 'perplexity.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-pit', 'pit', 'pit.com', 'https://pit.com', 'Pit', 'AI-built internal software for enterprise workflows.', 'The interesting bet is that enterprise software should be generated around the workflow, not bought as another SaaS shelf. Pit Studio maps messy processes, while Pit Cloud promises governance, audit trails, SSO, and tenant isolation for the custom apps it builds. Compared with no-code builders or agent sandboxes, this is closer to a forward-deployed product team. The risk is that every bespoke workflow can become consulting debt.', 5, '$16M seed for AI-built ops software', 'SaaS', 'Seed', '$16M', NULL, NULL, NULL, 'Europe', 'enterprise ai,workflow automation,internal tools,operations', 'Andreessen Horowitz, Lakestar', NULL, 1, 'pit.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-qodo', 'qodo', 'www.qodo.ai', 'https://www.qodo.ai', 'Qodo', 'AI code review, testing, and governance for engineering teams.', 'Most AI coding products still want to be copilots; the cleaner bet is fixing the review bottleneck instead. Qodo leads with 856.5K VS Code installs, 625K JetBrains installs, and a workflow spanning IDE, PR, CLI, and rules. That review-first posture feels more durable than one more generator wrapper, because teams adopting AI fastest mostly need help trusting what already got written. The risk is that model vendors eventually bundle enough verification to squeeze the middle layer.', 5, 'Review-first AI coding workflow', 'DevTools', 'Series B', '$70M', 2022, NULL, 'New York', 'US', 'developer tools,code review,ai coding,software quality', 'Qumra Capital, Maor Ventures, Phoenix Venture Partners, S Ventures, Square Peg, Susa Ventures, TLV Partners, Vine Ventures', '{"github": "https://github.com/Codium-ai", "twitter": "https://x.com/QodoAI", "linkedin": "https://www.linkedin.com/company/qodoai"}', 1, 'qodo.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-quantware', 'quantware', 'quantware.com', 'https://quantware.com', 'QuantWare', 'Commercial QPUs, peripherals, and foundry services for quantum builders.', 'The sharper quantum bet is not selling one more lab chip; it is turning QPUs into a manufacturable supply chain. QuantWare sells A-Line, D-Line, peripherals, foundry, and packaging services, and says it has shipped to 50+ customers across 20 countries. Unlike full-stack quantum computer builders, VIO is a component-platform wager: own the processor architecture other teams scale on. The risk is that the 10,000-qubit 2028 promise still has to survive physics and factory reality.', 5, 'Open QPU supply chain', 'Other', 'Series B', '$178M', NULL, NULL, NULL, 'Europe', 'quantum,hardware,qpu,semiconductors', 'Intel Capital, IQT, ETF Partners, FORWARD.one, Invest-NL Deep Tech Fund, InnovationQuarter Capital, Ground State Ventures, Graduate Ventures', '{"linkedin": "https://www.linkedin.com/company/quantware"}', 1, 'quantware.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, 