INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-scout-space', 'scout-space', 'www.scout.space', 'https://www.scout.space', 'Scout Space', 'In-space sensors and autonomy software for orbital awareness.', 'The sharp part is that space awareness needs distributed eyes in orbit, not only bigger ground systems. Scout Space sells Owl sensors, mission autonomy software, edge processing, and data tools for operators, and this round funds a 2,600-square-foot Virginia facility. Compared with a pure satellite builder, it is trying to become the sensing layer other spacecraft can carry. The risk is that government demand may hide how repeatable the commercial workflow is.', 4, '$18M Series A for orbital sensors', 'Other', 'Series A', '$18M', NULL, NULL, NULL, 'US', 'space,orbital awareness,sensors,autonomy', 'Washington Harbour Partners, Virginia Innovation Partnership Corporation, Noblis Ventures, Decisive Point, Fusion Fund', '{"linkedin": "https://www.linkedin.com/company/scoutdotspace"}', 1, 'scout-space.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.in