INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-secludy', 'secludy', 'secludy.com', 'https://secludy.com', 'Secludy', 'Privacy-safe synthetic data for regulated AI training.', 'The bet is that regulated AI teams need usable fake data, not another masking rulebook. Secludy shows differential-privacy presets, text and table anonymization examples, canary PII leakage tests, self-hosted VPC/on-prem deployment, and a claimed under-1-hour setup. Unlike legacy masking, it tries to preserve model utility while moving sensitive records out of scope. The risk is that privacy budgets become another specialist bottleneck.', 4, '$4M seed for DP synthetic data', 'AI / ML', 'Seed', '$4M', NULL, NULL, NULL, 'US', 'synthetic data,privacy,ai training,regulated data', 'Impression Ventures', NULL, 1, 'secludy.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_