INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-shapes', 'shapes', 'talk.shapes.inc', 'https://talk.shapes.inc', 'Shapes', 'Social AI chat app where people and bots share group conversations.', 'Most AI companion apps trap users in one-on-one confession booths; this points the format back toward messy group chat. The public surface shows 300+ models, message counts like 86.8K on individual characters, and mobile app links instead of a blank waitlist. That choice makes AI feel closer to Discord roleplay than a therapist clone. The hard part is moderation: social AI gets more interesting exactly where it gets harder to keep safe.', 4, 'AI companions in group chat', 'AI / ML', 'Seed', '$8M', 2023, '10-30', 'San Francisco', 'US', 'social ai,chat,consumer,ai companions', 'Lightspeed Venture Partners, Betaworks, Hartbeat Ventures, The Games Fund', NULL, 1, 'shapes.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_sta