INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-shyld-ai', 'shyld-ai', 'www.shyld.ai', 'https://www.shyld.ai', 'Shyld AI', 'Physical AI agents for hospital operations and disinfection.', 'The real bet is that hospital AI should act in the room, not sit in the chart. Shyld AI shows 3D LiDAR, radar, infrared sensing, edge GPUs, UV-C cycles, and a Stanford-linked 93% contamination reduction claim. Unlike ambient scribes, this is physical AI that changes OR turnover and infection-control workflows. The risk is whether hospital deployment speed matches the clinical evidence.', 4, '93% contamination reduction', 'HealthTech', 'Seed', '$13.4M', NULL, NULL, NULL, 'US', 'hospital operations,physical ai,infection control,edge ai', 'Aulis Capital', NULL, 1, 'shyld-ai.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-stitch', 'stitch', 'www.stitch.co', 'https://www.stitch.co', 'Stitch', 'Financial infrastructure OS for banks and fintechs.', 'The interesting move is treating bank modernization as a system-of-record problem, not a prettier payments API. Stitch exposes lending, cards, deposits, ledgers, applications, and live loan UI states, with $5B transacted in six months. Unlike point fintech rails, the bet is one stack that can be adopted module by module. The hard part is selling core infrastructure without inheriting every legacy edge case.', 5, '$5B transacted in six months', 'Fintech', 'Series A', '$25M', NULL, NULL, NULL, 'Global / Remote', 'financial infrastructure,core banking,ledgers,cards,lending', 'Andreessen Horowitz', NULL, 1, 'stitch.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-supabase', 'supabase', 'supabase.com', 'https://supabase.com', 'Supabase', 'The open source Firebase alternative.', 'The clever part is not calling itself an open-source Firebase alternative. The clever part is turning Postgres into the center of an entire developer stack: auth, storage, realtime, and edge functions. Where most backend platforms hide the database behind abstractions, Supabase leans into it. That makes the product more opinionated and easier to reason about than a generic backend cloud.', 4, 'Postgres as a platform', 'DevTools', 'Series B', '$80M', 2020, '100-200', 'Singapore', 'Global / Remote', 'database,open source,backend,postgres,firebase alternative', 'Felicis Ventures, Coatue Management, Y Combinator', '{"github": "https://github.com/supabase", "twitter": "https://x.com/supabase", "linkedin": "https://linkedin.com/company/supabase"}', 0, 'supabase.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-synera', 'synera', 'www.synera.io', 'https://www.synera.io', 'Synera', 'Agent platform for engineering workflows across CAD, FEA, costing, and reporting tools.', 'The interesting bet is that engineers do not need another copilot; they need a workbench where agents can operate CAD, FEA, cost, and reporting tools. Synera connects 80+ hardware-engineering systems with a node-based editor, 3D viewer, custom nodes, Python scripts, and token licensing. Unlike generic AI-for-manufacturing pitches, this starts from the messy CAx toolchain. The risk is that enterprise deployment turns the agents into services work.', 5, 'Agents across 80+ engineering tools', 'SaaS', 'Series B', '$40M', NULL, NULL, NULL, 'Europe', 'engineering,ai agents,cad,industrial software', 'Revaia', NULL, 1, 'synera.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-val-town', 'val-town', 'val.town', 'https://val.town', 'Val Town', 'Social website and API for writing and running code.', 'Putting running code inside a social feed sounds gimmicky until you try it. Every val is a URL, every function is deployable, and the product turns tiny scripts into shareable building blocks. That is a real bet against repo-first developer tooling. It feels closer to what Gists wanted to be than another serverless dashboard.', 4, 'Code as social media', 'DevTools', 'Seed', '$5.5M', 2022, '5-10', 'Brooklyn', 'US', 'social coding,serverless,developer tools,code sharing', 'Sequoia Capital Scout, Craft Ventures, Tom Preston-Werner', '{"github": "https://github.com/val-town", "twitter": "https://x.com/valabordar", "linkedin": "https://linkedin.com/company/val-town"}', 0, 'val-town.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-vapi', 'vapi', 'vapi.ai', 'https://vapi.ai', 'Vapi', 'Voice AI infrastructure for building, deploying, and managing phone agents.', 'The smart bet is that voice agents need latency infrastructure, not another bot builder. Vapi exposes call workflows, tool integrations, guardrails, SOC 2/HIPAA/PCI posture, and claims 1B calls, 2.5M+ agents, 750K developers, and sub-500ms latency. Compared with Twilio wrappers or contact-center suites, it sells the voice runtime beneath Ring-scale support. The risk is that voice AI becomes a commodity inside every CX platform.', 5, '1B calls on voice-agent platform', 'DevTools', 'Series B', '$50M', NULL, NULL, NULL, 'US', 'voice ai,ai agents,developer tools,customer support', 'Peak XV Partners', NULL, 0, 'vapi.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-vector', 'vector', 'www.vector.co', 'https://www.vector.co', 'Vector', 'Contact-level ad audiences and MCP analytics for B2B marketers.', 'The interesting choice is putting names back into ad targeting instead of hiding inside account segments. Vector shows visitor feeds, named buyer audiences, LinkedIn/Google/Reddit sync, 7.8% LinkedIn CTR, 17x ROI, and an MCP for asking campaign questions in Claude or ChatGPT. Unlike retargeting, it filters for exact ICP contacts already moving. The risk is that contact-level precision invites privacy pushback as fast as pipeline.', 4, '$10M Series A for Vector MCP', 'SaaS', 'Series A', '$10M', NULL, NULL, NULL, 'US', 'b2b marketing,advertising,mcp,marketing analytics', 'SignalFire, HubSpot Ventures', NULL, 1, 'vector.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = exclude